mapper.select:
select *
from study_team_member
where team_id = #{teamId}
  and user_id = #{userId}
  and status = 1
limit 1

select count(*)
from study_team_reminder
where team_id = #{teamId}
  and from_user_id = #{fromUserId}
  and to_user_id = #{toUserId}
  and create_time >= #{rangeStart}
  and create_time < #{rangeEnd}

select count(*)
from study_team_chat_message m
         left join study_team_chat_read_state rs
                   on rs.team_id = m.team_id
                       and rs.user_id = #{userId}
where m.team_id = #{teamId}
  and m.sender_user_id <> #{userId}
  and m.create_time >= #{sinceTime}
  and m.id > coalesce(rs.last_read_message_id, 0)

select last_read_message_id
from study_team_chat_read_state
where team_id = #{teamId}
  and user_id = #{userId}
limit 1

mapper.update:
update study_team_chat_message
set deleted_flag = 1,
    deleted_reason = #{deletedReason},
    deleted_time = #{deletedTime}
where id = #{messageId}
  and deleted_flag = 0

update study_team
set status = #{status}
where id = #{teamId}

update study_team_member
set status = #{status}
where team_id = #{teamId}

update study_team_member
set status = #{status}
where team_id = #{teamId}
  and user_id = #{userId}

update study_team_invitation
set status = #{status}
where id = #{invitationId}
